<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        console.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (exchange.id, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;fetchTicker failed with:&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, e.message)</span></span>
